SMOKE_PY = '\nfrom __future__ import annotations\nfrom html.parser import HTMLParser\nfrom pathlib import Path\nimport html, json, xml.etree.ElementTree as ET\n\nROOT = Path(__file__).resolve().parent\nSPEC_PATH = ROOT / "contracts" / "health_app.semantic.mcel"\n\ndef esc(v): return html.escape(str(v), quote=True)\ndef attrs(d): return " ".join(f\'{k}="{esc(v)}"\' for k,v in d.items() if v is not None)\ndef load_spec(path=None): return json.loads((Path(path) if path else SPEC_PATH).read_text(encoding="utf-8"))\ndef by_id(spec): return {n["id"]:n for n in spec["nodes"]}\n\ndef canonical_graph(spec):\n    nodes={n["id"]:{"id":n["id"],"type":n["type"],"channel":n["channel"],"signal":n["signal"],"subject":n["subject"],"value":n["value"],"unit":n["unit"],"source":n["source"],"provenance":n["provenance"],"symbol":n["symbol"],"image_uri":n.get("image_uri",""),"image_sha256":n.get("image_sha256",""),"image_width":n.get("image_width",""),"image_height":n.get("image_height",""),"timestamp":"2026-07-19T12:01:04Z","quality":n["quality"]} for n in spec["nodes"]}\n    edges={e["id"]:{"id":e["id"],"kind":e["kind"],"from":e["from"],"to":e["to"],"relation":e["relation"],"causal_link":"false","allowed_inferences":set(e.get("allowed_inferences",[])),"forbidden_inferences":set(e.get("forbidden_inferences",[]))} for e in spec["edges"]}\n    return {"nodes":nodes,"edges":edges}\n\ndef canonical_layout(spec):\n    nodes={}\n    for n in spec["nodes"]:\n        l=n["layout"]; p=l.get("ports",{})\n        nodes[n["id"]]={"anchor_x":str(l["anchor"][0]),"anchor_y":str(l["anchor"][1]),"width":str(l["size"][0]),"height":str(l["size"][1]),"z":str(l["z"]),"region":n["region"],"port_in":p.get("in",""),"port_out":p.get("out","")}\n    edges={e["id"]:{"route_kind":e["layout"]["route_kind"],"from_port":e["layout"]["from_port"],"to_port":e["layout"]["to_port"],"z":str(e["layout"]["z"])} for e in spec["edges"]}\n    controls={c["id"]:{"anchor_x":str(c["layout"]["anchor"][0]),"anchor_y":str(c["layout"]["anchor"][1]),"width":str(c["layout"]["size"][0]),"height":str(c["layout"]["size"][1])} for c in spec["controls"]}\n    return {"nodes":nodes,"edges":edges,"controls":controls}\n\ndef node_data(n, actual=None, tele=False):\n    l=n["layout"]; p=l.get("ports",{})\n    return {"data-mcel-node-id":n["id"],"data-mcel-node-type":n["type"],"data-mcel-channel":n["channel"],"data-mcel-signal":n["signal"],"data-mcel-symbol":n["symbol"],"data-mcel-subject":n["subject"],"data-mcel-value":n["value"],"data-mcel-unit":n["unit"],"data-mcel-source":n["source"],"data-mcel-provenance":n["provenance"],"data-mcel-image-uri":n.get("image_uri",""),"data-mcel-image-sha256":n.get("image_sha256",""),"data-mcel-image-width":n.get("image_width",""),"data-mcel-image-height":n.get("image_height",""),"data-mcel-timestamp":"2026-07-19T12:01:04Z","data-mcel-quality":n["quality"],"data-mcel-home-region":n["region"],"data-mcel-actual-region":actual or n["region"],"data-mcel-teleported":str(tele).lower(),"data-layout-anchor-x":l["anchor"][0],"data-layout-anchor-y":l["anchor"][1],"data-layout-width":l["size"][0],"data-layout-height":l["size"][1],"data-layout-z":l["z"],"data-layout-region":n["region"],"data-layout-port-in":p.get("in",""),"data-layout-port-out":p.get("out","")}\n\ndef edge_data(e, actual="factory_floor", tele=False):\n    l=e["layout"]\n    return {"data-mcel-edge-id":e["id"],"data-mcel-edge-kind":e["kind"],"data-mcel-from":e["from"],"data-mcel-to":e["to"],"data-mcel-relation":e["relation"],"data-mcel-causal-link":"false","data-mcel-allowed-inferences":",".join(e.get("allowed_inferences",[])),"data-mcel-forbidden-inferences":",".join(e.get("forbidden_inferences",[])),"data-mcel-home-region":"factory_floor","data-mcel-actual-region":actual,"data-mcel-teleported":str(tele).lower(),"data-layout-route-kind":l["route_kind"],"data-layout-from-port":l["from_port"],"data-layout-to-port":l["to_port"],"data-layout-z":l["z"]}\n\ndef control_data(c):\n    l=c["layout"]\n    return {"data-mcel-control":c["id"],"data-mcel-reveals":c["reveals"],"data-layout-control-id":c["id"],"data-layout-anchor-x":l["anchor"][0],"data-layout-anchor-y":l["anchor"][1],"data-layout-width":l["size"][0],"data-layout-height":l["size"][1]}\n\ndef port(n, which):\n    x,y=n["layout"]["anchor"]; w,h=n["layout"]["size"]\n    return {"west":(x-w/2,y),"east":(x+w/2,y),"north":(x,y-h/2),"south":(x,y+h/2)}.get(which,(x,y))\n\ndef route(e,nodes):\n    x1,y1=port(nodes[e["from"]],e["layout"]["from_port"]); x2,y2=port(nodes[e["to"]],e["layout"]["to_port"])\n    dx=max(60,abs(x2-x1)*.42); c1=x1-dx if e["layout"]["from_port"]=="west" else x1+dx\n    c2=x2+dx if e["layout"]["to_port"]=="east" else (x2-dx if e["layout"]["to_port"]=="west" else x2)\n    return f"M {x1:.1f} {y1:.1f} C {c1:.1f} {y1:.1f}, {c2:.1f} {y2:.1f}, {x2:.1f} {y2:.1f}"\n\ndef flow_kind(e): return {"SUPPORTS":"evidence_flow","OBSERVES":"image_flow","ANALOGOUS_TO":"bridge_flow","NAMES":"bridge_flow"}[e["kind"]]\n\ndef render_html_node(n):\n    x,y=n["layout"]["anchor"]; w,h=n["layout"]["size"]; img=""\n    if n["type"]=="image_frame": img=f\'<img class="node-image" src="../{esc(n["image_uri"])}" alt="{esc(n["label"])}"/>\'\n    return f\'<article class="health-node channel-{esc(n["channel"]).lower()} type-{esc(n["type"])}" style="--x:{x};--y:{y};--w:{w};--h:{h};" {attrs(node_data(n))}><div>{esc(n["symbol"])}</div>{img}<strong>{esc(n["label"])}</strong><span>{esc(n["channel"])} | {esc(n["unit"])}</span></article>\'\n\ndef render_html_edge(e): return f\'<i class="health-edge" data-mcel-flow-id="FLOW.{esc(e["id"])}" data-mcel-flow-kind="{flow_kind(e)}" {attrs(edge_data(e))}></i>\'\n\ndef render_standard_html(spec=None):\n    spec=spec or load_spec(); vw=spec["viewport"]["width"]; vh=spec["viewport"]["height"]\n    regions="".join(f\'<section class="health-region" style="left:{r["bbox"][0]}px;top:{r["bbox"][1]}px;width:{r["bbox"][2]}px;height:{r["bbox"][3]}px;" data-mcel-region="{esc(r["id"])}" data-mcel-region-role="{esc(r["role"])}"><h2>{esc(r["id"])}</h2></section>\' for r in spec["regions"])\n    nodes="".join(render_html_node(n) for n in spec["nodes"]); edges="".join(render_html_edge(e) for e in spec["edges"])\n    palette="".join(f\'<span data-mcel-palette-token="{esc(k)}">{esc(k)}</span>\' for k in spec["palette"])\n    controls="".join(f\'<button style="left:{c["layout"]["anchor"][0]-c["layout"]["size"][0]/2}px;top:{c["layout"]["anchor"][1]-c["layout"]["size"][1]/2}px;width:{c["layout"]["size"][0]}px;height:{c["layout"]["size"][1]}px;" {attrs(control_data(c))}>{esc(c["id"].split("_")[0])}</button>\' for c in spec["controls"])\n    return f\'\'\'<!doctype html><html data-mcel-app="HealthApp" data-mcel-contract="{esc(spec["contract"])}" data-mcel-renderer="standard_html" data-mcel-surface="html" data-mcel-layout-locked="false"><head><meta charset="utf-8"/><title>Health App Standard HTML</title><style>body{{margin:0;background:#050713;color:#eaf0ff;font-family:Inter,system-ui,sans-serif}}main{{position:relative;width:{vw}px;height:{vh}px;overflow:hidden}}h1{{position:absolute;left:40px;top:25px;margin:0}}.health-region{{position:absolute;border:1px solid rgba(141,169,255,.22);border-radius:24px;background:rgba(255,255,255,.04);padding:14px;color:#9aa8c5}}.health-node{{position:absolute;left:calc(var(--x)*1px);top:calc(var(--y)*1px);width:calc(var(--w)*1px);height:calc(var(--h)*1px);transform:translate(-50%,-50%);padding:8px;border:1px solid #8da9ff;border-radius:16px;background:#081020;display:grid;text-align:center;place-items:center;overflow:hidden}}.channel-bio_health{{border-color:#4df0b3}}.channel-sys_health{{border-color:#66a3ff}}.channel-bridge{{border-color:#f8c25c}}.type-image_frame{{border-color:#c89bff}}.node-image{{width:96px;height:54px;object-fit:cover}}.health-edge{{position:absolute;width:1px;height:1px;overflow:hidden}}button{{position:absolute;border-radius:999px;background:#0d1428;color:#eaf0ff;border:1px solid #8da9ff}}.palette{{position:absolute;left:60px;bottom:28px;display:flex;gap:18px;color:#9aa8c5}}</style></head><body><main><h1>Health App - Standard HTML</h1>{regions}<section>{edges}</section><section>{nodes}</section><section class="palette">{palette}</section><nav>{controls}</nav><script src="./health_app_surface.js"></script></main></body></html>\'\'\'\n\ndef render_svg_node(n, precision=False, tele=False, dx=0, dy=0):\n    x,y=n["layout"]["anchor"]; x+=dx; y+=dy; w,h=n["layout"]["size"]\n    color={"BIO_HEALTH":"#4df0b3","SYS_HEALTH":"#66a3ff","BRIDGE":"#f8c25c"}.get(n["channel"],"#c89bff")\n    filt=\' filter="url(#glow)"\' if precision else ""; img=""\n    if n["type"]=="image_frame": img=f\'<image href="../{esc(n["image_uri"])}" x="{-w/2+12}" y="{-h/2+14}" width="{w-24}" height="{min(72,h-28)}" opacity=".94"/>\'\n    label_y=26 if n["type"]=="image_frame" else 2; meta_y=46 if n["type"]=="image_frame" else 23\n    return f\'<g transform="translate({x:.1f} {y:.1f})" {attrs(node_data(n, actual="layout_stress_rail" if tele else n["region"], tele=tele))}><rect x="{-w/2}" y="{-h/2}" width="{w}" height="{h}" rx="18" fill="#070b18" stroke="{color}" stroke-width="1.5"{filt}/>{img}<text x="0" y="{label_y}" text-anchor="middle" class="node-label">{esc(n["label"])}</text><text x="0" y="{meta_y}" text-anchor="middle" class="node-meta">{esc(n["channel"])} | {esc(n["unit"])}</text></g>\'\n\ndef render_svg_edge(e,nodes,precision=False,tele=False):\n    color={"SUPPORTS":"#9df5d4","OBSERVES":"#c89bff","ANALOGOUS_TO":"#f8c25c","NAMES":"#f8c25c"}[e["kind"]]\n    width=5 if precision and e["kind"]=="ANALOGOUS_TO" else (3 if precision else 2.4); filt=\' filter="url(#line-glow)"\' if precision else ""; dash=\' stroke-dasharray="18 13"\' if e["kind"]=="ANALOGOUS_TO" else ""\n    return f\'<path d="{route(e,nodes)}" fill="none" stroke="{color}" stroke-width="{width}" opacity=".82"{filt} data-mcel-flow-id="FLOW.{esc(e["id"])}" data-mcel-flow-kind="{flow_kind(e)}" {attrs(edge_data(e, actual="layout_stress_rail" if tele else "factory_floor", tele=tele))}{dash}/>\'\n\ndef render_standard_svg(spec=None):\n    spec=spec or load_spec(); nodes=by_id(spec); vw=spec["viewport"]["width"]; vh=spec["viewport"]["height"]\n    regions="".join(f\'<rect x="{r["bbox"][0]}" y="{r["bbox"][1]}" width="{r["bbox"][2]}" height="{r["bbox"][3]}" rx="24" fill="rgba(255,255,255,.025)" stroke="rgba(141,169,255,.20)" data-mcel-region="{esc(r["id"])}" data-mcel-region-role="{esc(r["role"])}"/>\' for r in spec["regions"])\n    edges="".join(render_svg_edge(e,nodes) for e in spec["edges"]); node_svg="".join(render_svg_node(n) for n in spec["nodes"])\n    controls="".join(f\'<g transform="translate({c["layout"]["anchor"][0]} {c["layout"]["anchor"][1]})" {attrs(control_data(c))}><rect x="{-c["layout"]["size"][0]/2}" y="{-c["layout"]["size"][1]/2}" width="{c["layout"]["size"][0]}" height="{c["layout"]["size"][1]}" rx="19" fill="#0d1428" stroke="#8da9ff"/></g>\' for c in spec["controls"])\n    return f\'<svg xmlns="http://www.w3.org/2000/svg" width="{vw}" height="{vh}" viewBox="0 0 {vw} {vh}" data-mcel-app="HealthApp" data-mcel-contract="{esc(spec["contract"])}" data-mcel-renderer="standard_svg" data-mcel-surface="svg" data-mcel-layout-locked="false"><defs><style>.node-label{{fill:#eaf0ff;font-size:13px;font-weight:800}}.node-meta{{fill:#9aa8c5;font-size:10px}}</style></defs><rect width="{vw}" height="{vh}" fill="#050713"/><text x="40" y="60" fill="#eaf0ff" font-size="32">Health App - Standard SVG</text>{regions}<g>{edges}</g><g>{node_svg}</g><g>{controls}</g><script href="../surface/health_app_surface.js"/></svg>\'\n\ndef render_precision_svg(spec=None, snapshot=0, stress=False):\n    spec=spec or load_spec(); nodes=by_id(spec); vw=spec["viewport"]["width"]; vh=spec["viewport"]["height"]\n    regions="".join(f\'<rect x="{r["bbox"][0]}" y="{r["bbox"][1]}" width="{r["bbox"][2]}" height="{r["bbox"][3]}" rx="28" fill="rgba(255,255,255,.025)" stroke="rgba(141,169,255,.20)" data-mcel-region="{esc(r["id"])}" data-mcel-region-role="{esc(r["role"])}"/>\' for r in spec["regions"])\n    beauty="".join(f\'<path d="{esc(f["route"])}" fill="none" stroke="#f8c25c" stroke-width="2.2" opacity=".36" filter="url(#line-glow)" data-mcel-flow-id="{esc(f["id"])}" data-mcel-flow-kind="{esc(f["kind"])}" data-mcel-region-source="{esc(f["region_source"])}" data-mcel-region-target="{esc(f["region_target"])}"/>\' for f in spec["flows"])\n    node_parts=[]; edge_parts=[]\n    for n in spec["nodes"]:\n        tele=stress and snapshot%3==1 and n["id"] in {"IMAGE.graph_snapshot_001","BIO_HEALTH.activity_level"}\n        node_parts.append(render_svg_node(n, True, tele, 14 if tele else 0, 10 if tele else 0))\n    for e in spec["edges"]:\n        tele=stress and snapshot%4==2 and e["id"]=="EDGE.heartbeat_bridge"\n        edge_parts.append(render_svg_edge(e,nodes,True,tele))\n    controls="".join(f\'<g transform="translate({c["layout"]["anchor"][0]} {c["layout"]["anchor"][1]})" {attrs(control_data(c))}><rect x="{-c["layout"]["size"][0]/2}" y="{-c["layout"]["size"][1]/2}" width="{c["layout"]["size"][0]}" height="{c["layout"]["size"][1]}" rx="19" fill="#0d1428" stroke="#8da9ff"/></g>\' for c in spec["controls"])\n    palette="".join(f\'<circle cx="{58+i*148}" cy="1026" r="8" fill="{esc(color)}" data-mcel-palette-token="{esc(name)}"/>\' for i,(name,color) in enumerate(spec["palette"].items()))\n    return f\'<svg xmlns="http://www.w3.org/2000/svg" width="{vw}" height="{vh}" viewBox="0 0 {vw} {vh}" data-mcel-app="HealthApp" data-mcel-contract="{esc(spec["contract"])}" data-mcel-renderer="precision_spectacle_svg" data-mcel-surface="svg_js" data-mcel-willywonka="serious_machinery_with_style" data-mcel-layout-locked="false"><defs><style>.node-label{{fill:#eaf0ff;font-size:14px;font-weight:900}}.node-meta{{fill:#9aa8c5;font-size:10px}}</style><filter id="line-glow"><feGaussianBlur stdDeviation="3" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter><filter id="glow"><feDropShadow dx="0" dy="0" stdDeviation="8" flood-color="#8da9ff" flood-opacity=".75"/></filter></defs><rect width="{vw}" height="{vh}" fill="#02030a"/><text x="42" y="52" fill="#f8c25c" font-size="13">MCEL HEALTH APP - SHARED LAYOUT GRAMMAR</text><text x="42" y="100" fill="#eaf0ff" font-size="42">Health App</text>{regions}{beauty}<g>{"".join(edge_parts)}</g><g>{"".join(node_parts)}</g><g>{palette}</g><g>{controls}</g><script href="../surface/health_app_surface.js"/></svg>\'\n\ndef render_flog_snapshots(spec=None,count=12):\n    spec=spec or load_spec()\n    return [render_precision_svg(spec, snapshot=i, stress=True) for i in range(count)]\n\ndef parse_svg(x):\n    if isinstance(x,Path): return ET.fromstring(x.read_text(encoding="utf-8"))\n    s=str(x); return ET.fromstring(s if s.lstrip().startswith("<") else Path(s).read_text(encoding="utf-8"))\n\ndef semantic_from_attrs(d):\n    if "data-mcel-node-id" in d:\n        i=d["data-mcel-node-id"]; return "node",{"id":i,"type":d.get("data-mcel-node-type",""),"channel":d.get("data-mcel-channel",""),"signal":d.get("data-mcel-signal",""),"subject":d.get("data-mcel-subject",""),"value":d.get("data-mcel-value",""),"unit":d.get("data-mcel-unit",""),"source":d.get("data-mcel-source",""),"provenance":d.get("data-mcel-provenance",""),"symbol":d.get("data-mcel-symbol",""),"image_uri":d.get("data-mcel-image-uri",""),"image_sha256":d.get("data-mcel-image-sha256",""),"image_width":d.get("data-mcel-image-width",""),"image_height":d.get("data-mcel-image-height",""),"timestamp":d.get("data-mcel-timestamp",""),"quality":d.get("data-mcel-quality","")}\n    if "data-mcel-edge-id" in d:\n        i=d["data-mcel-edge-id"]; return "edge",{"id":i,"kind":d.get("data-mcel-edge-kind",""),"from":d.get("data-mcel-from",""),"to":d.get("data-mcel-to",""),"relation":d.get("data-mcel-relation",""),"causal_link":d.get("data-mcel-causal-link",""),"allowed_inferences":{x.strip() for x in d.get("data-mcel-allowed-inferences","").split(",") if x.strip()},"forbidden_inferences":{x.strip() for x in d.get("data-mcel-forbidden-inferences","").split(",") if x.strip()}}\n    return None\n\ndef layout_from_attrs(d):\n    if "data-mcel-node-id" in d:\n        return "node",d["data-mcel-node-id"],{"anchor_x":d.get("data-layout-anchor-x",""),"anchor_y":d.get("data-layout-anchor-y",""),"width":d.get("data-layout-width",""),"height":d.get("data-layout-height",""),"z":d.get("data-layout-z",""),"region":d.get("data-layout-region",""),"port_in":d.get("data-layout-port-in",""),"port_out":d.get("data-layout-port-out","")}\n    if "data-mcel-edge-id" in d:\n        return "edge",d["data-mcel-edge-id"],{"route_kind":d.get("data-layout-route-kind",""),"from_port":d.get("data-layout-from-port",""),"to_port":d.get("data-layout-to-port",""),"z":d.get("data-layout-z","")}\n    if "data-layout-control-id" in d:\n        return "control",d["data-layout-control-id"],{"anchor_x":d.get("data-layout-anchor-x",""),"anchor_y":d.get("data-layout-anchor-y",""),"width":d.get("data-layout-width",""),"height":d.get("data-layout-height","")}\n    return None\n\ndef extract_graph_from_svg(x):\n    root=parse_svg(x); out={"nodes":{},"edges":{}}\n    for el in root.iter():\n        item=semantic_from_attrs(el.attrib)\n        if item:\n            k,v=item; out["nodes" if k=="node" else "edges"][v["id"]]=v\n    return out\n\ndef extract_layout_from_svg(x):\n    root=parse_svg(x); out={"nodes":{},"edges":{},"controls":{}}\n    for el in root.iter():\n        item=layout_from_attrs(el.attrib)\n        if item:\n            k,i,v=item; out["nodes" if k=="node" else ("edges" if k=="edge" else "controls")][i]=v\n    return out\n\nclass H(HTMLParser):\n    def __init__(self): super().__init__(); self.graph={"nodes":{},"edges":{}}; self.layout={"nodes":{},"edges":{},"controls":{}}\n    def handle_starttag(self, tag, attrs_list):\n        d={k:v or "" for k,v in attrs_list}; item=semantic_from_attrs(d)\n        if item:\n            k,v=item; self.graph["nodes" if k=="node" else "edges"][v["id"]]=v\n        item=layout_from_attrs(d)\n        if item:\n            k,i,v=item; self.layout["nodes" if k=="node" else ("edges" if k=="edge" else "controls")][i]=v\n\ndef html_text(x):\n    if isinstance(x,Path): return x.read_text(encoding="utf-8")\n    s=str(x); return s if s.lstrip().startswith("<") else Path(s).read_text(encoding="utf-8")\n\ndef extract_graph_from_html(x):\n    p=H(); p.feed(html_text(x)); return p.graph\ndef extract_layout_from_html(x):\n    p=H(); p.feed(html_text(x)); return p.layout\n\ndef iter_svg_elements_with_attr(x,attr):\n    root=parse_svg(x)\n    for el in root.iter():\n        if attr in el.attrib: yield el\n\ndef build_outputs(root=None):\n    root=root or ROOT; spec=load_spec(root/"contracts/health_app.semantic.mcel")\n    (root/"surface").mkdir(exist_ok=True); (root/"snapshots").mkdir(exist_ok=True)\n    (root/"surface/standard_health_app.html").write_text(render_standard_html(spec),encoding="utf-8")\n    (root/"surface/standard_health_app.svg").write_text(render_standard_svg(spec),encoding="utf-8")\n    (root/"surface/precision_spectacle_health_app.svg").write_text(render_precision_svg(spec),encoding="utf-8")\n    for i,s in enumerate(render_flog_snapshots(spec,12)): (root/f"snapshots/snapshot_{i:03d}.svg").write_text(s,encoding="utf-8")\n'
TESTS = '\nfrom pathlib import Path\nimport hashlib\nfrom health_app_smoke import *\n\nROOT=Path(__file__).resolve().parents[1]\nSPEC_PATH=ROOT/"contracts/health_app.semantic.mcel"\nSTANDARD_HTML=ROOT/"surface/standard_health_app.html"\nSTANDARD_SVG=ROOT/"surface/standard_health_app.svg"\nSPECTACLE_SVG=ROOT/"surface/precision_spectacle_health_app.svg"\n\ndef file_sha256(path): return hashlib.sha256(path.read_text(encoding="utf-8").encode("utf-8")).hexdigest()\n\ndef boxes_overlap(a,b,pad=6):\n    ax1=a["x"]-a["w"]/2-pad; ax2=a["x"]+a["w"]/2+pad; ay1=a["y"]-a["h"]/2-pad; ay2=a["y"]+a["h"]/2+pad\n    bx1=b["x"]-b["w"]/2-pad; bx2=b["x"]+b["w"]/2+pad; by1=b["y"]-b["h"]/2-pad; by2=b["y"]+b["h"]/2+pad\n    return ax1<bx2 and ax2>bx1 and ay1<by2 and ay2>by1\n\ndef test_semantic_spec_has_shared_layout_grammar():\n    spec=load_spec(SPEC_PATH)\n    assert spec["contract"]=="HealthApp.SemanticDefinition.v2"\n    assert spec["app"]["definition_mode"]=="semantic_app_definition_with_shared_layout_grammar"\n    assert all("layout" in n for n in spec["nodes"])\n    assert all("layout" in e for e in spec["edges"])\n    assert all("layout" in c for c in spec["controls"])\n\ndef test_html_standard_svg_and_precision_svg_compile_to_same_graph():\n    spec=load_spec(SPEC_PATH); expected=canonical_graph(spec)\n    html_graph=extract_graph_from_html(render_standard_html(spec))\n    standard_graph=extract_graph_from_svg(render_standard_svg(spec))\n    precision_graph=extract_graph_from_svg(render_precision_svg(spec))\n    assert html_graph==expected\n    assert standard_graph==expected\n    assert precision_graph==expected\n    assert html_graph==standard_graph==precision_graph\n\ndef test_renderers_share_exact_layout_grammar():\n    spec=load_spec(SPEC_PATH); expected=canonical_layout(spec)\n    html_layout=extract_layout_from_html(render_standard_html(spec))\n    standard_layout=extract_layout_from_svg(render_standard_svg(spec))\n    precision_layout=extract_layout_from_svg(render_precision_svg(spec))\n    assert html_layout==expected\n    assert standard_layout==expected\n    assert precision_layout==expected\n    assert html_layout==standard_layout==precision_layout\n\ndef test_checked_in_surface_outputs_stay_aligned():\n    assert extract_graph_from_html(STANDARD_HTML)==extract_graph_from_svg(STANDARD_SVG)\n    assert extract_graph_from_svg(STANDARD_SVG)==extract_graph_from_svg(SPECTACLE_SVG)\n    assert extract_layout_from_html(STANDARD_HTML)==extract_layout_from_svg(STANDARD_SVG)\n    assert extract_layout_from_svg(STANDARD_SVG)==extract_layout_from_svg(SPECTACLE_SVG)\n\ndef test_nodes_and_controls_are_inside_viewport():\n    spec=load_spec(SPEC_PATH); vw=spec["viewport"]["width"]; vh=spec["viewport"]["height"]; m=spec["viewport"]["safe_margin"]\n    for n in spec["nodes"]:\n        x,y=n["layout"]["anchor"]; w,h=n["layout"]["size"]\n        assert x-w/2>=m and y-h/2>=m and x+w/2<=vw-m and y+h/2<=vh-m, n["id"]\n    for c in spec["controls"]:\n        x,y=c["layout"]["anchor"]; w,h=c["layout"]["size"]\n        assert x-w/2>=m and y-h/2>=m and x+w/2<=vw-m and y+h/2<=vh-m, c["id"]\n\ndef test_node_boxes_do_not_collide():\n    spec=load_spec(SPEC_PATH); boxes=[]\n    for n in spec["nodes"]:\n        x,y=n["layout"]["anchor"]; w,h=n["layout"]["size"]; boxes.append({"id":n["id"],"x":x,"y":y,"w":w,"h":h})\n    for i,a in enumerate(boxes):\n        for b in boxes[i+1:]: assert not boxes_overlap(a,b), f"{a[\'id\']} overlaps {b[\'id\']}"\n\ndef test_flog_snapshots_preserve_semantics_and_intended_layout():\n    spec=load_spec(SPEC_PATH); expected_graph=canonical_graph(spec); expected_layout=canonical_layout(spec)\n    for i,s in enumerate(render_flog_snapshots(spec,12)):\n        assert extract_graph_from_svg(s)==expected_graph, i\n        assert extract_layout_from_svg(s)==expected_layout, i\n\ndef test_precision_spectacle_has_no_orphan_beauty():\n    surface=render_precision_svg(load_spec(SPEC_PATH))\n    flows=list(iter_svg_elements_with_attr(surface,"data-mcel-flow-id"))\n    assert 20 <= len(flows) <= 96\n    allowed={"evidence_flow","signal_flow","bridge_flow","image_flow","timeline_flow","control_reveal"}\n    for f in flows:\n        assert f.attrib.get("data-mcel-flow-kind") in allowed\n        assert (f.attrib.get("data-mcel-from") and f.attrib.get("data-mcel-to")) or (f.attrib.get("data-mcel-region-source") and f.attrib.get("data-mcel-region-target"))\n\ndef test_real_image_artifacts_are_required_and_hashed():\n    graph=extract_graph_from_svg(SPECTACLE_SVG)\n    image_nodes=[n for n in graph["nodes"].values() if n["type"]=="image_frame"]\n    assert len(image_nodes)==3\n    for n in image_nodes:\n        p=ROOT/n["image_uri"]; assert p.exists()\n        assert n["image_width"]=="640" and n["image_height"]=="360"\n        assert file_sha256(p)==n["image_sha256"]\n\ndef test_heartbeat_bridge_is_analogous_not_same_or_causal():\n    graph=extract_graph_from_svg(SPECTACLE_SVG)\n    bridge=[e for e in graph["edges"].values() if e["from"]=="BIO_HEALTH.heart_rate" and e["to"]=="SYS_HEALTH.process_heartbeat"]\n    assert len(bridge)==1\n    bridge=bridge[0]\n    assert bridge["kind"]=="ANALOGOUS_TO"\n    assert bridge["relation"]=="rhythmic_liveness_signal"\n    assert bridge["causal_link"]=="false"\n    assert {"analogy","pattern_comparison"} <= bridge["allowed_inferences"]\n    assert {"identity","direct_causality","unit_mixing"} <= bridge["forbidden_inferences"]\n    assert not [e for e in graph["edges"].values() if e["kind"] in {"SAME_AS","CAUSES"} and e["from"].startswith("BIO_HEALTH.") and e["to"].startswith("SYS_HEALTH.")]\n\ndef test_surface_javascript_exposes_semantic_and_layout_extractors():\n    js=(ROOT/"surface/health_app_surface.js").read_text(encoding="utf-8")\n    for name in ["extractSemanticGraph","extractLayoutGrammar","preserveSemanticRidges","focusNode"]:\n        assert name in js\n'
JS = '/* Health App shared layout grammar smoke controller */\n(function(){\n  function all(sel, root){ return Array.prototype.slice.call((root||document).querySelectorAll(sel)); }\n  function csv(v){ return (v||"").split(",").map(function(x){return x.trim();}).filter(Boolean); }\n  function extractSemanticGraph(root){\n    root=root||document; var nodes={}, edges={};\n    all("[data-mcel-node-id]",root).forEach(function(el){var id=el.getAttribute("data-mcel-node-id");nodes[id]={id:id,type:el.getAttribute("data-mcel-node-type"),channel:el.getAttribute("data-mcel-channel"),signal:el.getAttribute("data-mcel-signal"),subject:el.getAttribute("data-mcel-subject"),value:el.getAttribute("data-mcel-value"),unit:el.getAttribute("data-mcel-unit"),source:el.getAttribute("data-mcel-source"),provenance:el.getAttribute("data-mcel-provenance")};});\n    all("[data-mcel-edge-id]",root).forEach(function(el){var id=el.getAttribute("data-mcel-edge-id");edges[id]={id:id,kind:el.getAttribute("data-mcel-edge-kind"),from:el.getAttribute("data-mcel-from"),to:el.getAttribute("data-mcel-to"),relation:el.getAttribute("data-mcel-relation"),causalLink:el.getAttribute("data-mcel-causal-link"),allowedInferences:csv(el.getAttribute("data-mcel-allowed-inferences")),forbiddenInferences:csv(el.getAttribute("data-mcel-forbidden-inferences"))};});\n    return {nodes:nodes,edges:edges};\n  }\n  function extractLayoutGrammar(root){\n    root=root||document; var nodes={}, edges={}, controls={};\n    all("[data-mcel-node-id]",root).forEach(function(el){var id=el.getAttribute("data-mcel-node-id");nodes[id]={anchorX:el.getAttribute("data-layout-anchor-x"),anchorY:el.getAttribute("data-layout-anchor-y"),width:el.getAttribute("data-layout-width"),height:el.getAttribute("data-layout-height")};});\n    all("[data-mcel-edge-id]",root).forEach(function(el){var id=el.getAttribute("data-mcel-edge-id");edges[id]={routeKind:el.getAttribute("data-layout-route-kind"),fromPort:el.getAttribute("data-layout-from-port"),toPort:el.getAttribute("data-layout-to-port")};});\n    all("[data-layout-control-id]",root).forEach(function(el){var id=el.getAttribute("data-layout-control-id");controls[id]={anchorX:el.getAttribute("data-layout-anchor-x"),anchorY:el.getAttribute("data-layout-anchor-y"),width:el.getAttribute("data-layout-width"),height:el.getAttribute("data-layout-height")};});\n    return {nodes:nodes,edges:edges,controls:controls};\n  }\n  function preserveSemanticRidges(){ return true; }\n  function focusNode(nodeId, root){ root=root||document; all("[data-mcel-node-id]",root).forEach(function(el){el.setAttribute("opacity",el.getAttribute("data-mcel-node-id")===nodeId?"1":".32");}); preserveSemanticRidges(); }\n  window.HealthAppSharedLayout = {extractSemanticGraph:extractSemanticGraph, extractLayoutGrammar:extractLayoutGrammar, preserveSemanticRidges:preserveSemanticRidges, focusNode:focusNode};\n})();\n'
README = '# Health App Shared Layout Grammar Smoke\n\nThis smoke patch aligns HTML, standard SVG, and precision SVG by compiling all three from one semantic definition and one shared layout grammar.\n\n## Run\n\n```bash\npython -m pytest tests/test_shared_layout_grammar_smoke.py -q\n```\n\n## Open\n\n```text\nsurface/standard_health_app.html\nsurface/standard_health_app.svg\nsurface/precision_spectacle_health_app.svg\n```\n\n## Checks\n\n- HTML, standard SVG, and precision SVG extract to the same semantic graph.\n- All three extract to the same layout grammar.\n- Edge routes use semantic ports.\n- Nodes and controls are inside the viewport.\n- Node boxes do not collide.\n- FLOG snapshots preserve intended semantics and layout.\n- Image artifacts exist and match declared hashes.\n'

def write(path: Path, text: str):
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(text, encoding="utf-8")

def build(target: Path):
    target.mkdir(parents=True, exist_ok=True)
    for rel, text in FRAMES.items():
        write(target / rel, text)
    write(target / "contracts" / "health_app.semantic.mcel", json.dumps(SPEC, indent=2, ensure_ascii=False))
    write(target / "health_app_smoke.py", SMOKE_PY)
    write(target / "surface" / "health_app_surface.js", JS)
    write(target / "tests" / "__init__.py", "")
    write(target / "tests" / "test_shared_layout_grammar_smoke.py", TESTS)
    write(target / "README.md", README)
    sys.path.insert(0, str(target))
    import health_app_smoke
    health_app_smoke.build_outputs(target)

def main() -> int:
    target = Path(sys.argv[1]) if len(sys.argv) > 1 else Path("health_app_shared_layout_grammar_smoke")
    build(target)
    print(f"Wrote Health App Shared Layout Grammar Smoke project to: {target}")
    print("Next:")
    print(f"  cd {target}")
    print("  python -m pytest tests/test_shared_layout_grammar_smoke.py -q")
    print("Open:")
    print(f"  {target / 'surface' / 'standard_health_app.html'}")
    print(f"  {target / 'surface' / 'standard_health_app.svg'}")
    print(f"  {target / 'surface' / 'precision_spectacle_health_app.svg'}")
    return 0

if __name__ == "__main__":
    raise SystemExit(main())
